"""Data models for the e-commerce system."""
import uuid


class Product:
    def __init__(self, product_id, name, price, category, in_stock=True):
        self.product_id = product_id
        self.name = name
        self.price = price
        self.category = category
        self.in_stock = in_stock

    def __repr__(self):
        return f"Product({self.product_id!r}, {self.name!r}, {self.price})"

    def __eq__(self, other):
        if not isinstance(other, Product):
            return NotImplemented
        return self.product_id == other.product_id

    def __hash__(self):
        return hash(self.product_id)


class Customer:
    def __init__(self, customer_id, name, email, tier="standard"):
        self.customer_id = customer_id
        self.name = name
        self.email = email
        self.tier = tier
        self.addresses = []

    def __repr__(self):
        return f"Customer({self.customer_id!r}, {self.name!r})"

    def add_address(self, address):
        self.addresses.append(address)
        return len(self.addresses)

    def get_primary_address(self):
        if self.addresses:
            return self.addresses[0]
        return None


class CartItem:
    def __init__(self, product, quantity):
        self.product = product
        self.quantity = quantity

    def __repr__(self):
        return f"CartItem({self.product.name!r}, qty={self.quantity})"

    def subtotal(self):
        return self.product.price * self.quantity


class Order:
    def __init__(self, order_id, customer, items, status="pending"):
        self.order_id = order_id
        self.customer = customer
        self.items = items
        self.status = status
        self.total = sum(item.subtotal() for item in items)

    def __repr__(self):
        return f"Order({self.order_id!r}, status={self.status!r}, total={self.total})"

    def __eq__(self, other):
        if not isinstance(other, Order):
            return NotImplemented
        return self.order_id == other.order_id

    def is_complete(self):
        return self.status == "delivered"

    def cancel(self):
        if self.status in ("pending", "confirmed"):
            self.status = "cancelled"
            return True
        return False

seed_files.repository.py:
"""Repository pattern for in-memory data storage."""


class ProductRepo:
    def __init__(self):
        self._store = {}

    def add(self, product):
        self._store[product.product_id] = product
        return product

    def find_by_id(self, product_id):
        return self._store.get(product_id)

    def find_all(self):
        return list(self._store.values())

    def find_by_category(self, category):
        return [p for p in self._store.values() if p.category == category]

    def find_in_stock(self):
        return [p for p in self._store.values() if p.in_stock]

    def update(self, product_id, **kwargs):
        product = self._store.get(product_id)
        if product is None:
            return None
        for key, value in kwargs.items():
            setattr(product, key, value)
        return product

    def delete(self, product_id):
        if product_id in self._store:
            del self._store[product_id]
            return True
        return False

    def count(self):
        return len(self._store)


class OrderRepo:
    def __init__(self):
        self._store = {}

    def add(self, order):
        self._store[order.order_id] = order
        return order

    def find_by_id(self, order_id):
        return self._store.get(order_id)

    def find_all(self):
        return list(self._store.values())

    def find_by_customer(self, customer_id):
        return [
            o for o in self._store.values()
            if o.customer.customer_id == customer_id
        ]

    def find_by_status(self, status):
        return [o for o in self._store.values() if o.status == status]

    def update_status(self, order_id, new_status):
        order = self._store.get(order_id)
        if order is None:
            return None
        order.status = new_status
        return order

    def delete(self, order_id):
        if order_id in self._store:
            del self._store[order_id]
            return True
        return False

    def count(self):
        return len(self._store)

    def total_revenue(self):
        return sum(o.total for o in self._store.values() if o.status != "cancelled")

