"""Business logic services for the e-commerce system."""
from models import Product, Customer, CartItem, Order
from repository import ProductRepo, OrderRepo


class CartService:
    def __init__(self):
        self._items = []

    def add_item(self, product, quantity=1):
        for item in self._items:
            if item.product == product:
                item.quantity += quantity
                return item
        new_item = CartItem(product, quantity)
        self._items.append(new_item)
        return new_item

    def remove_item(self, product_id):
        for i, item in enumerate(self._items):
            if item.product.product_id == product_id:
                return self._items.pop(i)
        return None

    def get_items(self):
        return list(self._items)

    def get_total(self):
        return sum(item.subtotal() for item in self._items)

    def clear(self):
        self._items.clear()

    def item_count(self):
        return sum(item.quantity for item in self._items)

    def is_empty(self):
        return len(self._items) == 0


class OrderService:
    def __init__(self, order_repo, product_repo):
        self._order_repo = order_repo
        self._product_repo = product_repo
        self._next_id = 1

    def create_order(self, customer, cart):
        if cart.is_empty():
            return None
        order = Order(
            order_id=str(self._next_id),
            customer=customer,
            items=cart.get_items(),
            status="confirmed"
        )
        self._next_id += 1
        self._order_repo.add(order)
        cart.clear()
        return order

    def cancel_order(self, order_id):
        order = self._order_repo.find_by_id(order_id)
        if order is None:
            return False
        return order.cancel()

    def get_order_history(self, customer_id):
        return self._order_repo.find_by_customer(customer_id)

    def get_pending_orders(self):
        return self._order_repo.find_by_status("pending")

    def complete_order(self, order_id):
        return self._order_repo.update_status(order_id, "delivered")

